import WidgetKit
import SwiftUI
import AppIntents

struct CalorieGoalIntent: AppIntent {
    static var title: LocalizedStringResource = "Calorie Goal"
    @Parameter(title: "Goal") var goal: Int
}

struct CalorieGoalWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "CalorieGoalWidget",
            intent: CalorieGoalIntent.self,
            provider: .static
        ) { entry in
            Text("Goal: \ (entry.goal) kcal")
        }
    }
}

